@Service
public class KafkaConsumerService {

    private static final Logger logger = LoggerFactory.getLogger(KafkaConsumerService.class);
    private static final String TOPIC = "my-events-topic"; // Consistent topic with producer
    private static final String GROUP_ID = "event-streaming-group";

    @KafkaListener(topics = TOPIC, groupId = GROUP_ID, containerFactory = "kafkaListenerContainerFactory")
    public void consumeEvent(Event event) {
        logger.info("Consumed event from topic {}: {}", TOPIC, event);
        // Process the consumed event here
        // For example, save to database, perform business logic, etc.
    }
}

