package com.example.kafkapoc.controller;

import com.example.kafkapoc.model.Event;
import com.example.kafkapoc.producer.KafkaProducerService;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.UUID;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private static final String TOPIC = "my-events-topic"; // Consistent topic with producer and consumer
    private final KafkaProducerService kafkaProducerService;

    public EventController(KafkaProducerService kafkaProducerService) {
        this.kafkaProducerService = kafkaProducerService;
    }

    @PostMapping
    public ResponseEntity<String> publishEvent(@RequestBody Event event) {
        // Assign a unique ID if not provided
        if (event.getId() == null || event.getId().isEmpty()) {
            event.setId(UUID.randomUUID().toString());
        }
        kafkaProducerService.sendEvent(TOPIC, event);
        return new ResponseEntity<>("Event published successfully: " + event.getId(), HttpStatus.OK);
    }
}